

import { NextResponse } from "next/server";
import { db } from "@/lib/db";

import { generateOfferLetter } from "@/lib/pdfGenerator";
import path from "path";
import fs from "fs";
import offerLetterTemplate from "../templates/offerLetterTemplate";
import { transporter } from "@/lib/email";


export async function POST(req: Request) {
  try {
    const { email } = await req.json();

    if (!email) {
      return NextResponse.json({ error: "Email is required" }, { status: 400 });
    }

    // Fetch user details
    const [users]: any[] = await db.query(
      "SELECT id, name, email, is_verified, program_id, university_id FROM users WHERE email = ?",
      [email]
    );

    if (!users || users.length === 0) {
      return NextResponse.json({ error: "User not found" }, { status: 404 });
    }

    const user = users[0];

    if (!user.is_verified) {
      return NextResponse.json({ error: "User is not verified" }, { status: 403 });
    }

    // Get program and university names
    const [programs]: any[] = await db.query("SELECT name FROM programs WHERE id = ?", [user.program_id]);
    const [universities]: any[] = await db.query("SELECT name FROM universities WHERE id = ?", [user.university_id]);

    if (!programs || programs.length === 0 || !universities || universities.length === 0) {
      return NextResponse.json({ error: "Invalid program or university" }, { status: 400 });
    }

    const program = programs[0];
    const university = universities[0];

    // Define offer letter file path
    const uploadsDir = path.join(process.cwd(), "uploads");
    if (!fs.existsSync(uploadsDir)) fs.mkdirSync(uploadsDir, { recursive: true });

    const filePath = path.join(uploadsDir, `Offer_Letter_${user.id}.pdf`);

    // Generate the offer letter only if it doesn't exist
    if (!fs.existsSync(filePath)) {
      const generatedFilePath = await generateOfferLetter(user, program.name, university.name);
      
      if (!fs.existsSync(generatedFilePath)) {
        return NextResponse.json({ error: "Failed to generate offer letter" }, { status: 500 });
      }
    }

    // Send the offer letter via email
    await transporter.sendMail({
      from: `"BringUrBuddy" <${process.env.EMAIL_USER}>`,
      to: user.email,
      subject: "Your Offer Letter - BringUrBuddy",
      html: offerLetterTemplate(user.name, program.name, university.name),
      attachments: [{ filename: "Offer_Letter.pdf", path: filePath }],
    });

    return NextResponse.json({ message: "Offer letter generated and sent successfully." });

  } catch (error) {
    console.error("Error generating offer letter:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}
