
export default function offerLetterTemplate(
  userName: string,
  programName: string,
  universityName: string
) {
  return `
      <div style="font-family: Arial, sans-serif; padding: 20px;">
        <h2 style="text-align: center;">Offer Letter</h2>
        <p>Dear <strong>${userName}</strong>,</p>
        <p>We are pleased to offer you admission to the <strong>${programName}</strong> program at <strong>${universityName}</strong>.</p>
        <p>Please find attached your official offer letter.</p>
        <p>Best regards,</p>
        <p><strong>BringUrBuddy Team</strong></p>
      </div>
    `;
}
